const AUTHOR_SCHEMA = {
  type: 'object',
  properties: {
    slug: { type: 'string' },
    final_title: { type: 'string' },
    final_metaDescription: { type: 'string' },
    words: { type: 'number' },
    preview_primary_present: { type: 'boolean' },
    preview_secondary_count: { type: 'number' },
    ok: { type: 'boolean' },
    error: { type: 'string' },
  },
  required: ['slug', 'final_title', 'final_metaDescription', 'words', 'ok'],
}

const VERIFY_SCHEMA = {
  type: 'object',
  properties: {
    slug: { type: 'string' },
    words: { type: 'number' },
    language_ok: { type: 'boolean' },
    preview_ok: { type: 'boolean' },
    fixed: { type: 'boolean' },
    final_title: { type: 'string' },
    final_metaDescription: { type: 'string' },
    notes: { type: 'string' },
  },
  required: ['slug', 'words', 'language_ok', 'preview_ok', 'fixed', 'final_title', 'final_metaDescription'],
}

function authorPrompt(s) {
  const sec = (s.secondary_keywords || []).join(', ')
  return `Esti un expert in educatie financiara din Romania si scrii pentru "Clubul Financiar" o lectie PREMIUM (continut platit — calitatea trebuie sa fie excelenta, de profunzime).

SUBIECT (draft, corecteaza orice greseala): ${s.draft_title}
Categorie: ${CATNAMES[s.category] || s.category}
Unghi/diferentiator (respecta-l): ${s.angle}
Cuvant-cheie principal (SEO): "${s.primary_keyword}"
Cuvinte-cheie secundare (SEO): ${sec}

CE SCRII:
O lectie COMPLETA si LUNGA (1800-2800 cuvinte de corp), in romana impecabila cu diacritice corecte. DOAR informatii extrem de importante, dense, actionabile — fara umplutura, fara generalitati de umplere. Context ROMANIA 2026: sume reale in lei, praguri, cote, legislatie/ANAF/BVB/BNR unde se aplica, exemple numerice concrete, scenarii pas-cu-pas, capcane frecvente, greseli de evitat, pasi de actiune, checklist-uri. Pedagogic si clar.

STRUCTURA (fragment HTML de CORP, NU pagina completa):
- Incepe DIRECT cu 2-3 paragrafe <p> de introducere (hook captivant) — FARA titlu, FARA <h1>.
- Apoi sectiuni cu <h2> (si <h3> unde ajuta), paragrafe <p>, liste <ul>/<li>, <strong> pentru accent.
- Include exemple numerice concrete (sume in lei, procente, calcule).
- Termina cu o sectiune practica (pasi de actiune sau checklist) si, daca e relevant, o sectiune scurta de greseli frecvente.
- INTERZIS: <h1>, disclaimer, butoane de navigare ("inapoi"), markdown, blocuri \`\`\`html. Doar HTML curat de corp.

REGULA SEO CRITICA — preview-ul gratuit:
Pe site, primele ~25% din lectie sunt vizibile gratuit (preview indexat de Google), restul e blocat in spatele paywall-ului premium. De aceea, PRIMELE 2-3 PARAGRAFE de introducere (primele ~150-180 de cuvinte, INAINTE de primul <h2>) TREBUIE sa contina NATURAL:
  (a) cuvantul-cheie principal "${s.primary_keyword}" — ideal in prima propozitie;
  (b) MAJORITATEA cuvintelor-cheie secundare de mai sus;
  (c) termenii importanti din titlu.
Integrare naturala si fluenta, ca o introducere atragatoare — NU insiruire de cuvinte-cheie / keyword stuffing. Acolo se concentreaza SEO-ul.

PASI:
1. Scrie lectia completa conform cerintelor.
2. Salveaz-o cu unealta Write in fisierul EXACT: ${SRC_DIR}/${s.slug}.html — continutul fisierului = DOAR fragmentul HTML de corp (incepe cu <p>...), nimic in plus.
3. Finalizeaza un TITLU corect, atractiv si corect gramatical, si o META DESCRIPTION de 140-160 caractere care contine natural "${s.primary_keyword}".
4. Returneaza structura ceruta (slug="${s.slug}", final_title, final_metaDescription, words=numar de cuvinte de corp, preview_primary_present, preview_secondary_count, ok).`
}

function verifyPrompt(s) {
  const sec = (s.secondary_keywords || []).join(', ')
  return `Esti redactor-sef la "Clubul Financiar". Verifici si FINALIZEZI o lectie PREMIUM scrisa de un autor. Fisier: ${SRC_DIR}/${s.slug}.html

Citeste fisierul cu Read. Verifica STRICT si CORECTEAZA in fisier (Edit/Write) unde gasesti probleme:
1. LIMBA: romana impecabila, diacritice corecte, FARA text amestecat sau cuvinte in alte limbi (ex. "Découvre", "ourile", "sis"), fara typo-uri, fara dezacorduri. Rescrie orice fraza stricata.
2. LUNGIME: minim ~1700 de cuvinte de corp. Daca e prea scurt, extinde cu continut valoros si concret.
3. SEO PREVIEW: primele 2-3 paragrafe (primele ~180 de cuvinte, inainte de primul <h2>) contin NATURAL cuvantul-cheie principal "${s.primary_keyword}" + majoritatea secundarelor (${sec}). Daca nu, rescrie introducerea ca sa le includa natural, fara keyword stuffing.
4. ACURATETE Romania 2026: cifre/praguri/cote/legislatie corecte (impozit pe venit, CASS, CAS, plafoane TVA, dobanzi BNR, praguri micro/PFA etc.). Corecteaza orice afirmatie factuala gresita sau invechita.
5. STRUCTURA HTML: doar fragment de corp (<p>, <h2>, <h3>, <ul>, <li>, <strong>); FARA <h1>, FARA disclaimer, FARA butoane "inapoi", FARA markdown sau \`\`\`html. Curata daca e cazul.
6. VALOARE: dens, actionabil, fara umplutura. Imbunatateste sectiunile slabe.

Daca lectia e deja excelenta, las-o asa. La final returneaza structura ceruta: slug="${s.slug}", words (final), language_ok, preview_ok, fixed (true daca ai editat fisierul), final_title (corect), final_metaDescription (140-160 caractere, cu "${s.primary_keyword}"), notes (foarte scurt).`
}

log(`Pornesc redactarea a ${SPECS.length} lectii premium (autor -> verificare).`)

const results = await pipeline(
  SPECS,
  (s) => agent(authorPrompt(s), { label: `author:${s.slug}`, phase: 'Author', schema: AUTHOR_SCHEMA, agentType: 'general-purpose', effort: 'high' })
            .then(r => ({ ...(r || {}), slug: s.slug })),
  (authored, s) => agent(verifyPrompt(s), { label: `verify:${s.slug}`, phase: 'Verify', schema: VERIFY_SCHEMA, agentType: 'general-purpose', effort: 'medium' })
            .then(v => ({ slug: s.slug, category: s.category, author: authored, verify: v || null }))
)

const done = results.filter(Boolean)
const failed = SPECS.filter(s => !done.find(d => d.slug === s.slug)).map(s => s.slug)
log(`Redactare terminata: ${done.length}/${SPECS.length} ok. Esuate: ${failed.length}`)
return { done, failed }
